INSERT INTO `dungeon_biome_hazards` (`id`, `biome`, `hazard_key`, `name`, `description`, `effect_json`, `spawn_weight`, `min_dungeon_level`, `max_dungeon_level`, `created_at`, `updated_at`) VALUES
(1, 'living caverns', 'loose_stone_echoes', 'Loose Stone Echoes', 'Unstable stone carries sound farther than expected.', '{\"stealth_penalty\": 1, \"hidden_trigger_bonus\": 1}', 90, 1, 10, '2026-05-08 22:57:10', '2026-05-08 22:57:10'),
(2, 'living caverns', 'spore_pockets', 'Spore Pockets', 'Pale fungal sacs burst when disturbed.', '{\"poison_risk\": 1, \"visibility\": \"low\"}', 55, 1, 15, '2026-05-08 22:57:10', '2026-05-08 22:57:10'),
(3, 'poison wetlands', 'toxic_mist', 'Toxic Mist', 'A green fog gathers close to the ground.', '{\"poison_damage\": 1, \"rest_penalty\": 1}', 90, 11, 25, '2026-05-08 22:57:10', '2026-05-08 22:57:10'),
(4, 'burned ruins', 'ash_gale', 'Ash Gale', 'Hot ash cuts sight lines and breathing rhythm.', '{\"fire_risk\": 1, \"accuracy_penalty\": 1}', 85, 21, 35, '2026-05-08 22:57:10', '2026-05-08 22:57:10'),
(5, 'frozen vaults', 'killing_cold', 'Killing Cold', 'Cold drains exposed flesh and slows movement.', '{\"ice_damage\": 1, \"dexterity_penalty\": 1}', 85, 31, 45, '2026-05-08 22:57:10', '2026-05-08 22:57:10'),
(6, 'undead catacombs', 'death_pressure', 'Death Pressure', 'The dead answer loud violence.', '{\"summon_risk\": 1, \"fear_pressure\": 1}', 70, 41, 55, '2026-05-08 22:57:10', '2026-05-08 22:57:10'),
(7, 'storm ocean trenches', 'surge_current', 'Surge Current', 'Water and lightning distort positioning.', '{\"lightning_risk\": 1, \"position_shift\": 1}', 80, 51, 65, '2026-05-08 22:57:10', '2026-05-08 22:57:10'),
(8, 'crystal mines', 'shard_refraction', 'Shard Refraction', 'Light splits into false movement and false targets.', '{\"illusion_risk\": 1, \"critical_variance\": 1}', 75, 61, 75, '2026-05-08 22:57:10', '2026-05-08 22:57:10'),
(9, 'cursed archive', 'memory_dust', 'Memory Dust', 'Dust from ruined books clings to names and thoughts.', '{\"memory_risk\": 1, \"wisdom_check\": 1}', 80, 71, 85, '2026-05-08 22:57:10', '2026-05-08 22:57:10'),
(10, 'void battlefield', 'gravity_scar', 'Gravity Scar', 'Broken gravity drags attacks and bodies off line.', '{\"void_risk\": 1, \"formation_break\": 1}', 85, 81, 95, '2026-05-08 22:57:10', '2026-05-08 22:57:10'),
(11, 'gateway beyond worlds', 'homeward_denial', 'Homeward Denial', 'The final gate resists every step toward return.', '{\"boss_pressure\": 2, \"phase_shift_bonus\": 1}', 100, 96, 100, '2026-05-08 22:57:10', '2026-05-08 22:57:10');
